&lt;p&gt;&lt;span style=&quot;&quot;&gt;भारत ने हमेशा&amp;nbsp;बात का प्रयत्न किया है - &amp;#39;&lt;strong&gt;परमाणु-ऊर्जा से लोगों की भलाई के कार्य करने का&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;गद्यांश के अनुसार:-&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;भारत ने सदैव इस बात का प्रयत्न किया है कि परमाणु ऊर्जा का प्रयोग विनाशकारी कार्यों के लिए न किया जाए, केवल &lt;strong&gt;लोकमंगल &lt;/strong&gt;के लिए उसका उपयोग हो।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;परमाणु-&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;पदार्थ का ऐसा अति सूक्ष्म कण जो अविभाज्य हो&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;भलाई-&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;कल्याण, उपकार,&amp;nbsp;अच्छाई,&amp;nbsp;हित,&amp;nbsp;नेकी।&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;विलोम&lt;/strong&gt; शब्द-&lt;strong&gt; &amp;#39;बुराई&amp;#39;&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;विध्वंस:-&lt;/span&gt;&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;तोड़-फोड़ करने वाला,&amp;nbsp;विनाश; बरबादी; क्षति; नाश।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विलोम &lt;/strong&gt;शब्द-&amp;nbsp;&lt;strong&gt;&amp;#39;निर्माण&amp;#39;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;रौब:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;शक्ति, सम्मान, भय, आतंक या कोई विशेष बात आदि से प्राप्त प्रसिद्धि।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ऊर्जा:-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अर्थ:&amp;nbsp;&lt;/span&gt;काम करने में व्यय होनेवाली शक्ति,&amp;nbsp;बल।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;मनुष्य को बात की चिंता हुई-&amp;nbsp;&lt;strong&gt;परमाणु-ऊर्जा के प्रयोग की दिशा न बदलने से होने वाले भयानक परिणामों की&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;गद्यांश के अनुसार:-&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;&lt;span style=&quot;&quot;&gt;परमाणु की महाशक्ति का विध्वंसकारी रूप मनुष्य ने हिरोशिमा तथा नागासाकी में देखा और उसे चिंता हुई कि यदि उसके &lt;strong&gt;प्रयोग की&lt;/strong&gt; &lt;strong&gt;दिशा न बदली गई तो बड़े भयावह परिणाम&lt;/strong&gt; होंगे।&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;परमाणु ऊर्जा&lt;/strong&gt;&amp;nbsp;वह &lt;strong&gt;ऊर्जा&lt;/strong&gt; है जिसे नियंत्रित (यानी, गैर-विस्फोटक)&lt;strong&gt; नाभिकीय अभिक्रिया&lt;/strong&gt; से उत्पन्न किया जाता है।&lt;/li&gt;
	&lt;li&gt;वर्तमान में &lt;strong&gt;विद्युत उत्पादन&lt;/strong&gt; के लिए &lt;strong&gt;वाणिज्यिक संयंत्र नाभिकीय विखण्डन&lt;/strong&gt; का उपयोग करते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;भयानक:-&lt;/span&gt;&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;जिसे देखने से भय लगता हो,&amp;nbsp;डरावना।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;परिणाम:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;strong&gt;परि + नाम =&amp;nbsp;&amp;nbsp;परिणाम&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;nbsp;&amp;#39;परि&amp;#39; &lt;/strong&gt;उपसर्ग और&lt;strong&gt; &amp;#39;नाम&amp;#39; &lt;/strong&gt;मूलशब्द&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;अर्थ:&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;नतीजा, निष्कर्ष, फल, अंजाम।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;ऊर्जा:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;अर्थ:&amp;nbsp;&lt;/span&gt;काम करने में व्यय होनेवाली शक्ति,&amp;nbsp;बल।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;उत्पादन:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;अर्थ:&amp;nbsp;&lt;/span&gt;पैदावार, उत्पत्ति, रचना, निर्मित पदार्थ, निर्माण।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;#39;इन अनुसंधानों का लाभ&amp;nbsp;&lt;/span&gt;&lt;strong&gt;&lt;u style=&quot;&quot;&gt;उठाया&amp;nbsp;&lt;/u&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;है।&amp;#39; वाक्य में रेखांकित पद है- &lt;strong&gt;&amp;#39;क्रिया&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;जो&lt;strong&gt; शब्द&lt;/strong&gt; किसी&lt;strong&gt; कार्य को&amp;nbsp;करने&lt;/strong&gt; या &lt;strong&gt;होने का बोध&lt;/strong&gt; कराते हैं। उन्हें &lt;strong&gt;क्रिया&lt;/strong&gt; कहते हैं।

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;जैसे-&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;उठना&lt;/strong&gt;,&amp;nbsp;&lt;/span&gt;हँसना, रोना, सोना, आना, जाना आदि&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;सीता &lt;strong&gt;दौड़ती &lt;/strong&gt;है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;क्रिया&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;के कुछ अन्य उदाहरण:-&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;गीता &lt;strong&gt;गाती&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;कुत्ता &lt;strong&gt;भोंकता &lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;दीप्ति खाना&lt;strong&gt; बनाती&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;राम बाण &lt;strong&gt;चलता&lt;/strong&gt; है|&lt;/li&gt;
	&lt;li&gt;मालिक नौकर को पैसे&lt;strong&gt; देता&lt;/strong&gt; है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:380px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;संज्ञा:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;किसी &lt;strong&gt;जाति, द्रव्य, गुण, भाव, व्यक्ति, स्थान&lt;/strong&gt;&amp;nbsp;आदि के नाम को&amp;nbsp;&lt;strong&gt;संज्ञा&lt;/strong&gt;&amp;nbsp;कहते हैं।&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;जैसे -&lt;/strong&gt; पशु (जाति), सुन्दरता (गुण), व्यथा (भाव), मोहन (व्यक्ति), दिल्ली (स्थान)।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;क्रियाविशेषण:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;वह &lt;strong&gt;शब्द &lt;/strong&gt;जो हमें &lt;strong&gt;क्रिया&lt;/strong&gt; की &lt;strong&gt;विशेषता &lt;/strong&gt;के बारे में बताते हैं, वे शब्द &lt;strong&gt;क्रिया विशेषण&lt;/strong&gt; कहलाते हैं।&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;पहचान-&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;color: rgb(32, 33, 36);   &quot;&gt;स&lt;/span&gt;चमुच, ठीक, अवश्य, कदाचित, ऐसे, वैसे, सहसा, तेज, सच, झूठ, धीरे, ध्यानपूर्वक, हंसते हुए, तेजी से, फटाफट आदि।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;जैसे -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;शेर &lt;strong&gt;धीरे-धीरे &lt;/strong&gt;आगे बढ़ता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;विशेषण:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;संज्ञा&lt;/strong&gt; अथवा &lt;strong&gt;सर्वनाम &lt;/strong&gt;शब्दों की &lt;strong&gt;विशेषता&lt;/strong&gt; (गुण, दोष, संख्या, परिमाण आदि) बताने वाले शब्द &lt;strong&gt;विशेषण&lt;/strong&gt; कहलाते हैं।&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;पहचान-&amp;nbsp;&lt;/span&gt;बड़ा, काला, लंबा, दयालु, भारी, सुन्दर, अच्छा, गन्दा, बुरा, एक, दो आदि।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;जैसे -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;टोकरी में&amp;nbsp;&lt;strong&gt;मीठे&amp;nbsp;&lt;/strong&gt;अंगूर हैं।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;#39;महाशक्ति&amp;#39;&lt;/strong&gt; में समास है- &lt;strong&gt;&amp;#39;कर्मधारय समास&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;#39;महाशक्ति&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;समास विग्रह&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;- महान है जो&amp;nbsp;शक्ति&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;कर्मधारय समास:-&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;इस समास का &lt;strong&gt;उत्तर पद प्रधान&lt;/strong&gt; होता है। इस समास में&lt;strong&gt; विशेषण-विशेष्य &lt;/strong&gt;और &lt;strong&gt;उपमेय-उपमान&lt;/strong&gt; से मिलकर बनते हैं उसे &lt;strong&gt;कर्मधारय समास&lt;/strong&gt; कहते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;समास विग्रह करने पर&lt;strong&gt; &amp;#39;है जो&amp;#39;, &amp;#39;जैसा&amp;#39; ,&amp;nbsp;&amp;#39;के समान&amp;#39; &lt;/strong&gt;शब्द आता हो।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उदाहरण:-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;महादेव =&lt;/strong&gt; महान है जो देव&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चन्द्रमुख =&lt;/strong&gt; चन्द्र जैसा मुख&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पीताम्बर =&lt;/strong&gt; पीत है जो अम्बर&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;नीलगगन =&lt;/strong&gt; नीला है जो गगन&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चरणकमल = &lt;/strong&gt;कमल के समान चरण&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:380px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;द्वंद्व समास:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;जिस समास में &lt;strong&gt;पूर्वपद &lt;/strong&gt;और &lt;strong&gt;उत्तरपद &lt;/strong&gt;दोनों ही प्रधान हों&amp;nbsp;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;समास&amp;nbsp;&lt;/span&gt;विग्रह &lt;/strong&gt;करने पर&lt;strong&gt; &amp;lsquo;और&amp;rsquo;&amp;nbsp;, &amp;lsquo; अथवा &amp;lsquo; , &amp;lsquo;या&amp;rsquo; ,&amp;nbsp; &amp;lsquo;एवं&amp;rsquo;&lt;/strong&gt; आता&amp;nbsp;हो,&amp;nbsp;&lt;span style=&quot;&quot;&gt;उसे&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;द्वंद्व&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;समास&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;कहते हैं।&lt;/span&gt;&amp;nbsp;&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण-&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;ठंडा-गर्म = ठंडा &lt;strong&gt;या&lt;/strong&gt; गर्म&lt;/li&gt;
				&lt;li&gt;माता-पिता = माता &lt;strong&gt;और&lt;/strong&gt; पिता&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;द्विगु समास:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;जिस&amp;nbsp;&lt;/span&gt;समास का &lt;strong&gt;पहला पद संख्यावाचक विशेषण&lt;/strong&gt; होता है और &lt;strong&gt;दूसरा पद उसका विशेष्य &lt;/strong&gt;होता है,&amp;nbsp;&lt;span style=&quot;&quot;&gt;उसे&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;द्विगु&amp;nbsp;&lt;/span&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;समास&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;कहते हैं।&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;&quot;&gt;इसमें&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;समूह &lt;/span&gt;या&amp;nbsp;&lt;span style=&quot;font-weight: 700; &quot;&gt;समाहार &lt;/span&gt;का बोध होता है&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण-&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;चैराहा =&amp;nbsp; चार राहों का &lt;strong&gt;समाहार/समूह&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;त्रिभुवन =&amp;nbsp; तीन भुवनों का &lt;strong&gt;समूह&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;strong&gt;बहुव्रीहि&lt;span style=&quot;&quot;&gt;:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;जिस&amp;nbsp;समास में &lt;strong&gt;कोई भी पद प्रधान नहीं &lt;/strong&gt;होता बल्कि समस्त पद किसी &lt;strong&gt;अन्य के विशेषण&lt;/strong&gt; &lt;strong&gt;का कार्य&lt;/strong&gt; करता है और यही&lt;strong&gt; तीसरा पद प्रधान &lt;/strong&gt;होता है, उसे&amp;nbsp;&lt;span style=&quot;font-weight: bold;  &quot;&gt;बहुव्रीहि&lt;/span&gt;&lt;span style=&quot;color: rgb(77, 81, 86);  &quot;&gt;&amp;nbsp;&lt;/span&gt;समास कहते है&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण-&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li style=&quot;box-sizing: inherit; line-height: 1.8; text-align: justify;&quot;&gt;&lt;strong&gt;दशानन =&lt;/strong&gt; दश है आनन (मुख) जिसके अर्थात् &lt;strong&gt;रावण&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;चतुर्भुज = &lt;/strong&gt;चार है भुजाएँ जिसकी अर्थात् &lt;strong&gt;विष्णु&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;परमाणु-ऊर्जा का कल्याणकारी रूप नहीं है-&amp;nbsp;&lt;strong&gt;हथियार/शस्त्र बनाना&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;गद्यांश के अनुसार:-&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;परमाणु-ऊर्जा का उपयोग&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;हल्के विस्फोट से सुरंग बनाने,&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;कृषि में&amp;nbsp;फलों एवं पौधों की नस्लों को संवृद्ध &lt;/strong&gt;करने&amp;nbsp;और&lt;strong&gt;&amp;nbsp;चिकित्सा में कैंसर &lt;/strong&gt;जैसे प्राणघाती रोग के उपचार में परमाणु से बहुत सहायता मिलती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;शस्त्र-&lt;/span&gt;&amp;nbsp;&lt;/strong&gt;कोई ऐसी चीज जिससे लड़ाई-झगड़े या युद्ध के समय शत्रु पर प्रहार किया जाता हो,&amp;nbsp;हथियार।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;विस्फोट:-&lt;/span&gt;&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अर्थ:&amp;nbsp;&lt;/strong&gt;फूटकर बाहर निकलना&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;सुरंग:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;अर्थ:&lt;/span&gt;&amp;nbsp;ज़मीन खोदकर अथवा समुद्र में बनाया गया रास्ता, गुफा&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;उपचार:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;अर्थ:&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;​चिकित्सा, इलाज, उपाय, निदान।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विलोम&lt;/strong&gt; शब्द- &lt;strong&gt;&amp;#39;अपचार&amp;#39;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;नस्ल:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;अर्थ:&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;​&lt;/span&gt;किसी जाति के पालतू पशुओं की एक विशेष प्रजाति,&amp;nbsp;किस्म&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;संवृद्धि:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;सम् +&amp;nbsp;वृद्धि =&amp;nbsp;संवृद्धि&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;#39;सम्&amp;#39; &lt;/span&gt;उपसर्ग और &lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;#39;वृद्धि&amp;#39; &lt;/span&gt;मूलशब्द&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अर्थ:&amp;nbsp;&lt;/strong&gt;बढ़ने की क्रिया या भाव,&amp;nbsp;बढ़ती, अधिकता&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
